-- ============================================================
-- 3. Create a vector index for fast similarity search
-- ============================================================
CREATE VECTOR INDEX idx_vector_demo_embedding
  ON vector_demo (embedding)
  ORGANIZATION NEIGHBOR PARTITIONS
  WITH TARGET ACCURACY 95
  DISTANCE COSINE
  PARAMETERS (type IVF, neighbor partitions 10);

-- ============================================================
-- 4. Example Queries
-- ============================================================

-- Query 1: Find top 5 most similar documents to the first entry
-- (In production, the query vector would come from your embedding model)
SELECT title, category,
       VECTOR_DISTANCE(embedding,
         (SELECT embedding FROM vector_demo WHERE id = 1),
         COSINE) AS similarity_distance
FROM vector_demo
WHERE id != 1
ORDER BY similarity_distance ASC
FETCH FIRST 5 ROWS ONLY;

-- Query 2: Filtered vector search — find similar 'database' category items only
SELECT title, category,
       VECTOR_DISTANCE(embedding,
         (SELECT embedding FROM vector_demo WHERE id = 1),
         COSINE) AS similarity_distance
FROM vector_demo
WHERE category = 'database'
ORDER BY similarity_distance ASC
FETCH FIRST 3 ROWS ONLY;

-- Query 3: Show all records with their vector dimensions and similarity scores
SELECT id, title, category,
       VECTOR_DIMENSION(embedding) AS dims,
       VECTOR_DISTANCE(embedding,
         (SELECT embedding FROM vector_demo WHERE ROWNUM = 1),
         COSINE) AS distance_from_first
FROM vector_demo
ORDER BY distance_from_first ASC;
